'use client';

import React from 'react';

import type { ImageFileSelection } from '@/shared/contracts/files';
import { Card } from '@/shared/ui/primitives.public';

import { FileManagerProvider } from '../contexts/FileManagerContext';
import { FileManagerBulkActions } from './file-manager/FileManagerBulkActions';
import { FileManagerContent } from './file-manager/FileManagerContent';
import { FileManagerFilters } from './file-manager/FileManagerFilters';
import { FileManagerHeader } from './file-manager/FileManagerHeader';
import { FileManagerModals } from './file-manager/FileManagerModals';

interface FileManagerProps {
  onSelectFile?: (files: ImageFileSelection[]) => void;
  mode?: 'view' | 'select';
  showFileManager?: boolean;
  selectionMode?: 'single' | 'multiple';
  autoConfirmSelection?: boolean;
  showFolderFilter?: boolean;
  defaultFolder?: string;
  showBulkActions?: boolean;
  showTagSearch?: boolean;
  filepathFilter?: (filepath: string) => boolean;
}

export type FileManagerRuntimeValue = {
  onSelectFile?: (files: ImageFileSelection[]) => void;
};

export const FileManagerRuntimeContext = React.createContext<FileManagerRuntimeValue | null>(null);

export default function FileManager(props: FileManagerProps): React.JSX.Element {
  const {
    onSelectFile,
    mode,
    selectionMode,
    autoConfirmSelection,
    showFolderFilter,
    defaultFolder,
    showBulkActions,
    showTagSearch,
    filepathFilter,
  } = props;

  const runtime = React.useContext(FileManagerRuntimeContext);
  const resolvedOnSelectFile = onSelectFile ?? runtime?.onSelectFile;

  const providerProps = React.useMemo(() => {
    const config: Partial<React.ComponentProps<typeof FileManagerProvider>> = {};
    if (resolvedOnSelectFile !== undefined) config.onSelectFile = resolvedOnSelectFile;
    if (mode !== undefined) config.mode = mode;
    if (selectionMode !== undefined) config.selectionMode = selectionMode;
    if (autoConfirmSelection !== undefined) config.autoConfirmSelection = autoConfirmSelection;
    if (showFolderFilter !== undefined) config.showFolderFilter = showFolderFilter;
    if (defaultFolder !== undefined) config.defaultFolder = defaultFolder;
    if (showBulkActions !== undefined) config.showBulkActions = showBulkActions;
    if (showTagSearch !== undefined) config.showTagSearch = showTagSearch;
    if (filepathFilter !== undefined) config.filepathFilter = filepathFilter;
    return config;
  }, [
    resolvedOnSelectFile,
    mode,
    selectionMode,
    autoConfirmSelection,
    showFolderFilter,
    defaultFolder,
    showBulkActions,
    showTagSearch,
    filepathFilter,
  ]);


  return (
    <FileManagerProvider {...providerProps}>
      <Card variant='glass' padding='md' className='text-white shadow-xl border-border/60'>
        <FileManagerHeader />
        <FileManagerFilters />
        <FileManagerBulkActions />
        <FileManagerContent />
        <FileManagerModals />
      </Card>
    </FileManagerProvider>
  );
}

import React from 'react';

import type { EntityModalProps } from '@/shared/contracts/ui/modals';
import type { Asset3DRecord } from '@/shared/contracts/viewer3d';
import { Badge } from '@/shared/ui/primitives.public';
import { MetadataItem, UI_GRID_RELAXED_CLASSNAME } from '@/shared/ui/navigation-and-layout.public';
import { StatusBadge } from '@/shared/ui/data-display.public';
import { DetailModal, DetailModalSection } from '@/shared/ui/templates/modals';
import { formatDateTime, formatFileSize } from '@/shared/utils/formatting';

interface AssetPreviewModalProps extends EntityModalProps<Asset3DRecord> {}

export function AssetPreviewModal(props: AssetPreviewModalProps): React.JSX.Element | null {
  const { isOpen, onClose, item: previewAsset } = props;

  if (!previewAsset) return null;

  return (
    <DetailModal
      isOpen={isOpen}
      onClose={onClose}
      title={previewAsset.name ?? previewAsset.filename}
      subtitle={previewAsset.filepath}
      size='lg'
    >
      <div className='space-y-6'>
        <div className={`${UI_GRID_RELAXED_CLASSNAME} sm:grid-cols-2 lg:grid-cols-3`}>
          <MetadataItem label='Size' value={formatFileSize(previewAsset.size)} />
          <MetadataItem label='MIME Type' value={previewAsset.mimetype} />
          <MetadataItem
            label='Visibility'
            value={
              <StatusBadge
                status={previewAsset.isPublic ? 'Public' : 'Private'}
                variant={previewAsset.isPublic ? 'success' : 'neutral'}
                size='sm'
              />
            }
          />
          <MetadataItem label='Category' value={previewAsset.categoryId ?? '—'} />
          <MetadataItem
            label='Added'
            value={formatDateTime(previewAsset.createdAt)}
            valueClassName='text-xs text-gray-400'
          />
          <MetadataItem
            label='Last Modified'
            value={formatDateTime(previewAsset.updatedAt)}
            valueClassName='text-xs text-gray-400'
          />
        </div>

        {(previewAsset.tags ?? []).length > 0 && (
          <DetailModalSection title='Tags'>
            <div className='flex flex-wrap gap-2'>
              {(previewAsset.tags ?? []).map((tag) => (
                <Badge key={tag} variant='secondary' className='text-[10px]'>
                  {tag}
                </Badge>
              ))}
            </div>
          </DetailModalSection>
        )}

        {previewAsset.description && (
          <DetailModalSection title='Description' className='border-border bg-card/30'>
            <p className='text-sm text-gray-300 leading-relaxed'>{previewAsset.description}</p>
          </DetailModalSection>
        )}

        <DetailModalSection title='System Metadata' className='border-border bg-gray-950'>
          <pre className='max-h-64 overflow-auto text-[11px] text-gray-400 font-mono leading-relaxed'>
            {JSON.stringify(previewAsset.metadata ?? {}, null, 2)}
          </pre>
        </DetailModalSection>
      </div>
    </DetailModal>
  );
}

