'use client';

import Image from 'next/image';
import Link from 'next/link';
import React, { useCallback } from 'react';

import { type ImageFileSelection } from '@/shared/contracts/files';
import type { ExpandedImageFile } from '@/shared/contracts/products/drafts';
import { Button, Card, Badge } from '@/shared/ui/primitives.public';

import {
  useFileManagerActions,
  useFileManagerConfig,
  useFileManagerData,
  useFileManagerUIState,
} from '../../contexts/FileManagerContext';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


export function FileManagerGrid(): React.JSX.Element {
  const { filteredFiles } = useFileManagerData();
  const { selectedFiles, setPreviewFile } = useFileManagerUIState();
  const { mode } = useFileManagerConfig();
  const { handleToggleSelect, handleDelete } = useFileManagerActions();

  const getFileKind = useCallback((filepath: string) => {
    const clean = (filepath || '').trim();
    if (!clean) return 'other';
    if (clean.startsWith('data:')) return 'base64';
    if (/^https?:\/\//i.test(clean)) {
      try {
        const url = new URL(clean);
        if (url.pathname.includes('/uploads/')) return 'upload';
      } catch (error) {
        logClientError(error);
        return 'link';
      }
      return 'link';
    }
    if (
      clean.includes('/uploads/') ||
      clean.startsWith('/uploads/') ||
      clean.startsWith('uploads/')
    )
      return 'upload';
    return 'other';
  }, []);

  const resolveFolder = useCallback(
    (filepath: string): string => {
      const kind = getFileKind(filepath);
      if (kind === 'base64') return 'base64';
      if (kind === 'link') {
        try {
          return new URL(filepath).hostname || 'link';
        } catch (error) {
          logClientError(error);
          return 'link';
        }
      }
      const clean = filepath.replace(/^\/+/, '');
      const parts = clean.split('/');
      if (parts.length === 0) return 'uploads';
      if (parts[0] === 'uploads') return parts[1] ?? 'uploads';
      return parts[0] || 'uploads';
    },
    [getFileKind]
  );

  const handleClick = (file: ExpandedImageFile): void => {
    if (mode === 'select') {
      handleToggleSelect({ id: file.id, filepath: file.filepath });
    } else {
      setPreviewFile(file);
    }
  };

  return (
    <div className='grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-4'>
      {filteredFiles.map((file: ExpandedImageFile) => (
        <Card
          key={file.id}
          className={`relative border-2 transition-all cursor-pointer overflow-hidden ${
            selectedFiles.some((f: ImageFileSelection) => f.id === file.id)
              ? 'border-blue-500 bg-blue-500/5'
              : 'border-transparent hover:border-gray-700'
          }`}
          onClick={(): void => handleClick(file)}
        >
          <Badge
            variant='neutral'
            className='absolute left-2 top-2 bg-gray-900/80 text-[10px] font-bold uppercase tracking-wide z-10'
          >
            {resolveFolder(file.filepath)}
          </Badge>
          <div className='aspect-square relative w-full'>
            <Image src={file.filepath} alt={file.filename} fill className='object-cover' />
          </div>
          <div className='p-2'>
            <p className='text-center text-sm truncate font-medium' title={file.filename}>
              {file.filename}
            </p>
            {(file.tags ?? []).length > 0 && (
              <div className='mt-1 flex flex-wrap justify-center gap-1'>
                {(file.tags ?? []).slice(0, 3).map((tag: string) => (
                  <Badge key={tag} variant='neutral' className='bg-card/70 text-[10px] font-normal'>
                    #{tag}
                  </Badge>
                ))}
              </div>
            )}
            <div className='mt-1 text-center text-xs text-gray-400'>
              {file.products.map(({ product }: { product: { id: string; name: string } }) => (
                <Link
                  key={product.id}
                  href={`/admin/products/${product.id}/edit`}
                  className='hover:underline block truncate'
                  onClick={(e) => e.stopPropagation()}
                >
                  {product.name}
                </Link>
              ))}
            </div>
            <div className='mt-2 flex justify-center gap-2'>
              <Button
                variant='secondary'
                size='sm'
                className='h-7 px-2 text-[11px]'
                onClick={(e: React.MouseEvent<HTMLButtonElement>): void => {
                  e.stopPropagation();
                  setPreviewFile(file);
                }}
              >
                View
              </Button>
              <Button
                variant='destructive'
                size='sm'
                className='h-7 px-2 text-[11px]'
                onClick={(e: React.MouseEvent<HTMLButtonElement>): void => {
                  e.stopPropagation();
                  void handleDelete(file.id);
                }}
              >
                Delete
              </Button>
            </div>
          </div>
        </Card>
      ))}
    </div>
  );
}

'use client';

import React, { useMemo } from 'react';

import { FilterPanel, StandardDataTablePanel } from '@/shared/ui/templates.public';
import { Pagination, UI_CENTER_ROW_SPACED_CLASSNAME } from '@/shared/ui/navigation-and-layout.public';
import { RefreshButton } from '@/shared/ui/forms-and-actions.public';
import type { FilterField } from '@/shared/contracts/ui/panels';
import type { LabeledOptionDto } from '@/shared/contracts/base';

import { useFileUploadEventsPanelContext } from './context/FileUploadEventsPanelContext';
import { useFileUploadEventsContext } from '../../contexts/FileUploadEventsContext';
import { useFileUploadEventsTableProps } from '../../hooks/useFileUploadEventsTableProps';
import { resolveFileUploadEventsFilterUpdate } from './FileUploadEventsTable.helpers';

const FILE_UPLOAD_STATUS_OPTIONS: Array<LabeledOptionDto<'all' | 'success' | 'error'>> = [
  { value: 'all', label: 'All statuses' },
  { value: 'success', label: 'Success' },
  { value: 'error', label: 'Error' },
];

export function FileUploadEventsTable(): React.JSX.Element {
  const tableProps = useFileUploadEventsTableProps();
  const { title, description } = useFileUploadEventsPanelContext();
  const {
    total,
    refetch,
    isFetching,
    page,
    setPage,
    pageSize,
    setPageSize,
    status,
    setStatus,
    category,
    setCategory,
    projectId,
    setProjectId,
    query,
    setQuery,
    fromDate,
    setFromDate,
    toDate,
    setToDate,
    handleResetFilters,
  } = useFileUploadEventsContext();

  const filterConfig: FilterField[] = useMemo(
    () => [
      {
        key: 'status',
        label: 'Status',
        type: 'select',
        options: FILE_UPLOAD_STATUS_OPTIONS,
      },
      { key: 'category', label: 'Category', type: 'text', placeholder: 'studio, cms, products…' },
      { key: 'projectId', label: 'Project ID', type: 'text', placeholder: 'project id…' },
      { key: 'fromDate', label: 'From Date', type: 'date' },
      { key: 'toDate', label: 'To Date', type: 'date' },
    ],
    []
  );

  const filterValues = useMemo(
    () => ({
      status,
      category,
      projectId,
      fromDate,
      toDate,
    }),
    [status, category, projectId, fromDate, toDate]
  );

  const handleFilterChange = (key: string, value: unknown) => {
    setPage(1);
    const update = resolveFileUploadEventsFilterUpdate(key, value);
    if (!update) return;

    if (update.key === 'status') {
      setStatus(update.value);
      return;
    }

    const filterSetters = {
      category: setCategory,
      projectId: setProjectId,
      fromDate: setFromDate,
      toDate: setToDate,
    } as const;
    filterSetters[update.key](update.value);
  };

  const footer = (
    <div className='px-4 pb-2'>
      <Pagination
        variant='panel'
        page={page}
        pageSize={pageSize}
        totalCount={total}
        onPageChange={setPage}
        onPageSizeChange={(size) => {
          setPage(1);
          setPageSize(size);
        }}
        isLoading={isFetching}
      />
    </div>
  );

  const filters = (
    <FilterPanel
      filters={filterConfig}
      values={filterValues}
      search={query}
      searchPlaceholder='filename, error, source…'
      onFilterChange={handleFilterChange}
      onSearchChange={(q) => {
        setPage(1);
        setQuery(q);
      }}
      onReset={handleResetFilters}
      showHeader={false}
      compact
    />
  );

  const actions = (
    <div className={UI_CENTER_ROW_SPACED_CLASSNAME}>
      <div className='text-[11px] text-gray-500'>
        Total: <span className='text-gray-300'>{total}</span>
      </div>
      <RefreshButton
        onRefresh={(): void => {
          void refetch();
        }}
        isRefreshing={isFetching}
      />
    </div>
  );

  return (
    <StandardDataTablePanel
      {...tableProps}
      title={title}
      description={description}
      filters={filters}
      footer={footer}
      actions={actions}
      variant='flat'
    />
  );
}

